import re, sys

with open("src/app/login/page.tsx", "r", encoding="utf-8") as f:
    content = f.read()

new_img = '<img src={dk ? "data:image/png;base64," : "data:image/png;base64,"} alt="Aurovista" style={{width:56,height:56,objectFit:"contain",marginBottom:"2.5rem"}} />'

pattern = r'<img src=.+?cloudinary.+?/>'
m = re.search(pattern, content, re.DOTALL)
if m:
    content = content[:m.start()] + new_img + content[m.end():]
    print("OK replaced")
else:
    print("NOT FOUND")
    sys.exit(1)

with open("src/app/login/page.tsx", "w", encoding="utf-8") as f:
    f.write(content)
